def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        priority = 60.0 + np.sqrt(cap) * 30 + np.log1p(cap * 10) * 15
        oscillation = 0.0
        phase_shift = ((idx * 7) % 13) / 13.0
        if usage > 5:
            priority += 6000 * np.power(usage, 1.15)
            if cap > 12:
                priority += 120 * np.cbrt(cap) + 40 * np.cos(cap * 1.7 + phase_shift * np.pi)
            else:
                priority -= 50 * usage
            for i in range(1, 7):
                oscillation += ((-1)**i) * np.sin(usage * np.pi * i * 0.9 + phase_shift * 2) * 22 / i
            for j in range(3, 10):
                if j % 2 == 0:
                    priority += np.exp(-usage / (j/3)) * 50
                else:
                    priority -= np.log1p(usage * j) * 18
        elif 4 < usage <= 5:
            delta = usage - 4
            priority += 2200 * delta ** 2 + 180 * (1 - np.sqrt(delta))
            for k in range(1, 10):
                oscillation += np.cos(usage * np.pi * (k ** 1.4) + phase_shift) * 30 / k
            if int(cap * 4) % 4 == 0:
                priority += 50 * np.tan(cap / 12) * np.cos(phase_shift * np.pi)
        elif 3 < usage <= 4:
            priority += 1400 * (usage - 3)**2.5
            for m in range(1, 15):
                val = usage ** m
                if val < 0.35:
                    oscillation += val * 12 / m
                    if m % 6 == 0:
                        oscillation += 5 * m
                else:
                    oscillation += (1 - val) * 20 / (m + 3)
                    if m == 13 and usage > 3.5:
                        oscillation += 25
            if cap % 2.7 < 0.6:
                priority += 45 * np.sin(cap * 3.5) * np.sin(phase_shift * 4)
        elif 2 < usage <= 3:
            priority += 1100 * (usage - 2) ** 3
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.5:
                    oscillation += pwr * 28 / n
                    if n % 5 == 2:
                        oscillation -= 3 * n
                else:
                    oscillation += (1 - pwr) * 14 / (n + 2)
                    if n == 17 and usage > 2.6:
                        oscillation += 18
            if cap % 1.9 < 0.4:
                priority += 40 * np.cos(cap * 2.2) + 10 * np.sin(phase_shift * 8)
        elif 1 < usage <= 2:
            priority += 1000 * (usage - 1) ** 2.2
            for o in range(1, 25):
                usage_pow = usage ** o
                if usage_pow < 0.55:
                    oscillation += usage_pow * 30 / o
                    if o % 4 == 3:
                        oscillation -= 4 * o
                else:
                    oscillation += (1 - usage_pow) * 16 / (o + 4)
                    if o == 22 and usage > 1.8:
                        oscillation += 20
            if cap % 1.6 < 0.35:
                priority += 38 * np.cos(cap * 1.8) + 12 * np.cos(phase_shift * 5)
        elif 0.7 < usage <= 1:
            priority += 120 * (1 - usage)
            for p in range(1, 15):
                ratio_pow = usage ** p
                oscillation += (np.tanh(ratio_pow * np.pi / 4) - 0.35) * 15 / p
                if usage < 0.06 * p:
                    priority -= 9 * p
            if cap < 0.2:
                priority += np.sqrt(cap) * 300 + 5 * phase_shift
            elif cap < 1.0:
                priority += np.log1p(cap * 18) * 40
            else:
                priority += (cap % 7) * 25
        else:
            priority += 350 * (1 - usage)**2
            for q in range(1, 25):
                rpow = usage ** q
                oscillation += (np.sin(rpow * np.pi / 7) - 0.28) * 16 / q
                if usage < 0.01 * q:
                    priority -= 15 * q
            if cap < 0.01:
                priority += np.sqrt(cap) * 400 + 20 * phase_shift
            elif cap < 1.5:
                priority += np.log1p(cap * 28) * 50
            else:
                priority += (cap % 8) * 32
        priority += oscillation
        if cap < 0.03:
            priority += 85 + 10 * np.sin(cap * 50)
            if usage > 0.8:
                priority += 110
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 8):
                    priority -= r * np.exp(-usage * 25) * 1.1
        elif cap < 1.1:
            priority += 55 + 5 * np.cos(cap * 30)
            if usage > 0.9:
                priority += 70
            elif usage < 0.22:
                priority -= 35
            for s in range(1, 7):
                mod_val = int(cap * 1400) % (s + 5)
                if mod_val == 0 or mod_val == 1:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 55
                for t in range(1, 8):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 110
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 40 + 3 * phase_shift
        prox_score = 0
        if int(cap * 3000) % 23 == 0:
            prox_score += 18
        if int(cap * 1000) % 29 == 0:
            prox_score -= 14
        if int(cap * 200) % 11 == 0:
            prox_score += 17
        for w in range(1, 11):
            diff = abs(usage - w / 12)
            if diff < 0.015:
                prox_score += 23 / w
            elif diff < 0.04:
                prox_score += 13 / w
            else:
                prox_score -= 5 / w
        for x in range(1, 10):
            modchk = int(cap * 1700) % (x + 11)
            if modchk == 0:
                prox_score += x * 6
            elif modchk == 4:
                prox_score -= x * 5
        for y in range(1, 6):
            modchk = int(usage * 1700) % (y + 8)
            if modchk == 0:
                prox_score += 12 * y
            elif modchk == 4:
                prox_score -= 9 * y
        priority += prox_score
        if usage < 0.004:
            for z in range(1, 10):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 14
        if cap > 3.0:
            if cap % 1 < 0.04:
                priority += 50
            if (int(cap * 3000) % 29 == 0) and (usage > 0.75):
                priority += 75
            for bb in range(1, 7):
                if (int(cap * 700) % (bb + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
